INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('troia-comporta','Private Troia & Comporta Tour from Lisbon - Ruins, Wine & Beaches','https://www.viator.com/tours/Lisbon/Private-Troia-and-Comporta-Tour-from-Lisbon-Ruins-Wine-and-Coast/d538-349639P18','8 to 9 hours (approx.)','Lisbon, Almada, Sesimbra, or Setúbal (including hotels, apartments, Airbnbs, cruise terminal, and Lisbon Airport).','Escape into one of Portugal’s best-kept secrets — a discreet retreat favored by artists. This private tour blends Roman history, the luxury of Troia Marina, and the secluded elegance of Comporta. You will cross the Sado River by ferry, explore over 2,000 years of history at Roman ruins, and visit the unique Carrasqueira Palafitic Pier. The day includes a wine experience at the iconic Herdade da Comporta and visits to wild Atlantic beaches, all guided by a local expert.',ARRAY['Private transportation in air-conditioned vehicle','Exclusive private experience with a local expert guide','Ferry crossing across the Sado River (vehicle + passengers included)','Guided visit to the Roman Ruins of Tróia (admission included)','Wine experience at Herdade da Comporta (tasting included)','Bottled water throughout the day','Flexible itinerary with scenic stops and hidden gems along the coast','Personalized recommendations for restaurants and local experiences','Pickup and drop-off at your accommodation (Lisbon, Setúbal, Sesimbra or Almada)']::text[],ARRAY['Lunch (curated recommendations provided based on preferences)']::text[],ARRAY['Group size']::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('arrabida-sesimbra','Private Tour from Lisbon – Arrábida, Sesimbra & Coastal Boat Ride','https://www.viator.com/tours/Lisbon/Private-Full-Day-Arrabida-and-Sesimbra-with-Boat-Tour-from-Lisbon/d538-349639P12','6 to 8 hours (approx.)','Pickup and drop-off available anywhere in Lisbon, Almada, Sesimbra, or Setúbal, including hotels, apartments, Airbnbs, the Port of Lisbon (cruise terminal), and Lisbon Airport.','Leave Lisbon behind and explore the stunning beauty of southern Lisbon on this unforgettable full day private tour. Discover one of the best fresh markets in the world, wind through the dramatic landscapes of the Arrábida Natural Park, and enjoy a scenic boat ride along the coastline. With flexible boat options including dolphin watching, snorkeling, or kayaking, and visits to historic Sesimbra and Cape Espichel, this private experience is crafted just for you.',ARRAY['Private transportation','Boat Tour (3 different options)','Private local tour guide village','Lunch (when choosing the “Arrabida Discovery Boat Tour with Lunch”)','Private pick up and drop off anywhere in Lisbon, Setúbal, Sesimbra and Almada','Bottled water','Air-conditioned vehicle']::text[],ARRAY['Lunch (unless selecting the “Arrabida Discovery Boat Tour with Lunch” option)','Personal expenses']::text[],ARRAY['Dolphin watching boat ride','Snorkeling boat ride','Kayaking boat ride','Arrabida Discovery Boat Tour with Lunch']::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('sintra-cascais-hidden','Private Sintra & Cascais Tour from Lisbon – Hidden Gems & Wine','https://www.viator.com/tours/Lisbon/Sintra-and-Cascais-Hidden-Gems-Private-Tour-with-Wine-Tasting/d538-349639P10','8 to 10 hours (approx.)','Pick-up and drop-off available anywhere in Lisbon, Almada, Sesimbra, or Setúbal (Hotels, apartments, Airbnbs, cruise terminal, or airport).','Discover the cultural gems and coastal charm of Sintra and Cascais on this customizable private tour. Travel in comfort with private transport as you explore fairytale palaces, visit the westernmost point of Europe, and enjoy a wine tasting in the historic Colares region. This flexible itinerary allows you to skip crowds with expert local guidance while enjoying local pastries and breathtaking coastal views.',ARRAY['Private transportation','Air-conditioned vehicle','One palace ticket and wine tour and tasting OR two palace tickets per person','Bottled water','Certified tour guide','Private pick up and drop off anywhere in Lisbon, Setúbal, Almada and Sesimbra','Local pastry']::text[],ARRAY['Lunch']::text[],ARRAY['Choice of one palace ticket and wine tour and tasting OR two palace tickets per person']::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('azeitao-cheese','Private Cheese-Making & Wine Tour: Azeitão & Sesimbra from Lisbon','https://www.viator.com/tours/Lisbon/Azeitao-Cheese-Private-Workshop-with-Wine-and-Food-Tasting/d538-349639P9','8 hours 30 minutes (approx.)','Pick Up and Drop Off included anywhere in Lisbon, Almada, Setúbal and Sesimbra. (Extra charge of €30 per person for pick ups from Tróia and Comporta, or take the ferry to Setúbal for included pick up).','Explore beyond Lisbon on this private day tour that combines traditional gastronomy with history. Visit the famous Mercado do Livramento in Setúbal, participate in a hands-on Azeitão cheese-making workshop, and enjoy a wine tasting at Farm Catralvos. The day concludes with a visit to the medieval Sesimbra Castle and scenic views of the Arrábida Natural Park and the Cristo Rei sanctuary.',ARRAY['Air-conditioned vehicle','Private transportation','All Fees and Taxes','Private Azeitão cheese workshop','Toasts, regional bread, fresh cheese, buttery Azeitão cheese, homemade jam/chutney and muscat wine','Bottled water','Private Pick Up and Drop Off anywhere in Lisbon, Almada, Setúbal and Sesimbra','Winery entrances and tastings']::text[],ARRAY['Lunch']::text[],ARRAY[]::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('tomar-coimbra','Private Tomar & Coimbra Tour from Lisbon – Templars & Heritage','https://www.viator.com/tours/Lisbon/From-Lisbon-Private-Full-Day-Tour-to-Tomar-and-Coimbra/d538-349639P8','8 to 9 hours (approx.)','Pickup and drop-off available anywhere in Lisbon, Almada, Sesimbra, or Setúbal. We collect from hotels, apartments, Airbnbs, the Port of Lisbon (cruise terminal), and Lisbon Airport.','Discover Portugal’s historic heartlands on this private full‑day tour to Tomar—home to the medieval Templar fortress—and the scholarly city of Coimbra. Explore the UNESCO-listed Convent of Christ and the historic University of Coimbra, featuring the baroque Joanina Library, with a dedicated guide and flexible schedule.',ARRAY['All Fees and Taxes','Private transportation','Air-conditioned vehicle','All entrances and tickets','Certified Tour Guide','Bottled water','Local pastry']::text[],ARRAY['Lunch']::text[],ARRAY['Price varies by group size']::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('setubal-wine','Private Evora & Alentejo Wine Tour from Lisbon - Local Traditions','https://www.viator.com/tours/Lisbon/Private-Full-Day-Wine-Tour-in-Setubal-Region-from-Lisbon/d538-349639P6','9 to 11 hours (approx.)','Pickup and drop-off available anywhere in Lisbon, Almada, Sesimbra, or Setúbal. (Hotels, apartments, Airbnbs, the Port of Lisbon, and Lisbon Airport)','Explore the soul of southern Alentejo, a land of slow rhythms and bold flavors. This private full-day experience from Lisbon takes you to the UNESCO-listed city of Évora to walk ancient streets and see the Chapel of Bones. You will visit two carefully selected wineries to taste award-winning wines, visit a traditional cork production site, and enjoy a traditional local lunch. Led by a local host, the tour is relaxed and personally adapted to your interests.',ARRAY['Private pick-up and drop-off at your accommodation','Dedicated local guide/host','All entrance fees (including Chapel of Bones and Évora city visits)','Guided visits and wine tastings at two carefully selected wineries','Traditional tastings of local cheeses and cured meats','Visit a traditional cork production site','Bottled water throughout the day']::text[],ARRAY['Lunch (time is reserved at a selected traditional restaurant, but the meal is not included)']::text[],ARRAY['Winery selection (Joao Portugal Ramos Wines, Enoturismo Cartuxa, Pera-grave, Ervideira, or Herdade do Esporao)']::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('fatima-nazare-obidos','Private Lisbon to Fátima, Nazaré & Óbidos Tour – Spirit & Charm','https://www.viator.com/tours/Lisbon/Private-Full-day-Fatima-Nazare-Obidos-Tour-from-Lisbon/d538-349639P5','8 hours (approx.)','Private pickup and drop off anywhere in Lisbon, Setubal, Sesimbra and Almada.','Maximize your time in Portugal with this private, full-day excursion to Fatima, Nazare, and Obidos from Lisbon. Following hotel pick-up, you’ll visit the pilgrimage site of Fatima, explore the fishing village of Nazare for lunch and beach views, and wander the medieval town of Obidos where you can try ginjinha cherry liqueur. This private tour includes roundtrip transportation, a local pastry, and a liqueur tasting.',ARRAY['All Fees and Taxes','Air-conditioned vehicle','Private transportation','Alcoholic Beverages (Ginginha tasting)','Certified tour guide','Private pickup and drop off','Bottled water','Local pastry']::text[],ARRAY['Lunch']::text[],ARRAY[]::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('south-lisbon-golf','Private Tile Painting Workshop, Wine & Sesimbra Tour from Lisbon','https://www.viator.com/tours/Lisbon/Full-Day-Golf-and-Wine-tasting-Private-Tour-in-South-Lisbon/d538-349639P4','8 to 9 hours (approx.)','Pickup and drop-off available anywhere in Lisbon, Almada, Sesimbra, or Setúbal. We collect from hotels, apartments, Airbnbs, the Port of Lisbon (cruise terminal), and Lisbon Airport.','Discover the Portugal most travelers never see on this private tour from Lisbon blending authentic traditions, beautiful landscapes and local experiences. Feel the atmosphere of the famous Livramento Market, admire the stunning coastal scenery of Arrábida and discover Portuguese craftsmanship as you paint your own traditional azulejo. Experience the traditions of the Azeitão region with wine and cheese tastings and enjoy the charm of Sesimbra, a picturesque fishing village. Enjoy iconic views from Cristo Rei and explore Portugal at your own pace.',ARRAY['Private transportation','Bottled water','Certified tour guide','Air-conditioned vehicle','Alcoholic Beverages','Tiles Making Workshop and Tile Shipping','All entrances','Cheese tasting']::text[],ARRAY['Lunch']::text[],ARRAY['Winery selection (Farm Catralvos, Jose Maria de Fonseca, or Bacalhoa Vinhos de Portugal)']::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('southern-lisbon-wine','Lisbon: Private Arrabida Wine tour - All-Inclusive, Food & Views','https://www.viator.com/tours/Lisbon/Private-Wine-Tour-with-Food-and-Wine-Tasting-in-Southern-Lisbon/d538-349639P3','7 to 9 hours','Pickup and drop-off available anywhere in Lisbon, Almada, Sesimbra, or Setúbal (hotels, apartments, cruise terminal, and airport). Also available in Tróia and Comporta (extra charge applies).','Escape Lisbon for a private journey through the Arrabida and Setubal regions. This all-inclusive tour combines prestigious and family-run wineries with cultural landmarks, traditional tile-making, and a visit to one of the world''s best fresh markets. Savor local delicacies like Azeitão cheese and Sado River oysters while exploring the natural beauty of the Arrabida Natural Park.',ARRAY['Visit 2 or 3 wineries (depending on the experience you choose)','Wine tastings (reds, whites, and Moscatel)','Fresh oysters from the Sado River and traditional Azeitão cheese','Traditional Portuguese lunch in a local restaurant in Azeitão (depending on the selected option)','Private transportation with bottled water','Local certified guide','Visit to Livramento Market, Tile Factory and Arrabida Natural Park','Hotel pickup and drop-off','Admission tickets for included stops (as specified in itinerary)']::text[],ARRAY['Gratuities']::text[],ARRAY['Number of wineries visited (2 or 3)','Inclusion of lunch in Azeitão','Choice between Private or Small Group tour']::text[]);
INSERT INTO public.builder_tour_sources (tour_key,title,source_url,duration_text,pickup_zone,blurb,inclusions,exclusions,varies_by_option) VALUES ('wild-beaches-picnic','Private Lisbon Coastal Tour – Arrábida, Sesimbra and Beach Picnic','https://www.viator.com/tours/Lisbon/Wild-Beaches-and-Picnic-Experience/d538-349639P1','7 hours 30 minutes (approx.)','Private pick-up and drop-off from and to Lisbon, Setúbal, Almada and Sesimbra.','Skip the hassle of research and route planning and embark on a full-day, private Jeep adventure through Arrábida Natural Park and Sesimbra from Lisbon. Experience rugged landscapes, serene beaches, and local culture off the beaten path. Discover the historic fishing village of Sesimbra and its grand castle, enjoy panoramic views from Cabo Espichel, visit the Mercado do Livramento in Setúbal, and much more. Enjoy a private picnic with local products at your beach of choice.',ARRAY['Private transportation','Air-conditioned vehicle','Private Picnic with local cheeses, bread, smoked meats, pastries, fruit, wine, juice and water','Bottled water','All Fees and Taxes','Local certified tour guide','Private pick-up and drop-off in Lisbon, Setúbal, Almada and Sesimbra']::text[],ARRAY['Lunch (other than picnic)']::text[],ARRAY['Pickup location','Picnic beach location choice','Choice between Cabo Espichel or Sesimbra Castle (itinerary sequence varies)']::text[]);
